    private readonly StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9: StatusStrip default renderer changed; set explicitly to preserve appearance
        _statusStrip.RenderMode = ToolStripRenderMode.System;
        Controls.Add(_statusStrip);
    }

    // WFO1000: Properties on UserControl must have explicit serialization configuration
    [DefaultValue(null)]
    public string DisplayName { get; set; }

    [DefaultValue(0)]
    public int MaxItems { get; set; }

    /// <summary>
    /// Shows an editor dropdown. In .NET 9 the DropDownControl parameter
    /// changed from nullable to non-nullable, so callers must guard against null.
    /// </summary>
    public void ShowEditor(IWindowsFormsEditorService editorService, Control control)
    {
        if (control is not null)
        {
            editorService.DropDownControl(control);
        }
    }
}

